  ('science', 'K', 2, 'K.livingnonliving', NULL, 'Living things need ___ to grow.', '["glass","food and water","paint","nothing"]', 1, 'All living things need food and water.', 10),
  ('science', 'K', 2, 'K.livingnonliving', NULL, 'Which one is NOT living?', '["A car","A tree","A fish","A bird"]', 0, 'A car does not eat or grow, so it is non-living.', 10),
  ('science', 'K', 2, 'K.livingnonliving', NULL, 'Which living thing can grow bigger?', '["A ball","A baby","A spoon","A sock"]', 1, 'Babies are living and grow bigger over time.', 10),
  ('science', 'K', 2, 'K.livingnonliving', NULL, 'A flower is ___.', '["not living","living","a kind of rock","a toy"]', 1, 'Plants like flowers are living things.', 10),
  ('science', 'K', 2, 'K.livingnonliving', NULL, 'Which one is non-living?', '["A cat","A worm","A plant","A rock"]', 3, 'A rock does not grow or need food — it is non-living.', 10),
  ('science', 'K', 2, 'K.weather', NULL, 'What do we call the white, cold flakes that fall in winter?', '["Sun","Sand","Snow","Wind"]', 2, 'Snow falls when it is very cold.', 10),
  ('science', 'K', 2, 'K.weather', NULL, 'On a clear sunny day, the sky usually looks ___.', '["blue","green","purple","black"]', 0, 'A clear daytime sky looks blue.', 10),
  ('science', 'K', 2, 'K.weather', NULL, 'What falls from clouds when it rains?', '["Rocks","Water","Leaves","Sand"]', 1, 'Rain is water falling from clouds.', 10),
  ('science', 'K', 2, 'K.weather', NULL, 'Which weather is warm and bright?', '["Snowy","Rainy","Windy","Sunny"]', 3, 'Sunny weather is warm and bright.', 10),
  ('science', 'K', 2, 'K.weather', NULL, 'What should you wear when it is cold and snowy?', '["Sunglasses only","Sandals","A swimsuit","A warm coat"]', 3, 'A warm coat keeps you warm in cold weather.', 10),
  ('science', 'K', 2, 'K.weather', NULL, 'Clouds are made of tiny drops of ___.', '["glass","sand","dirt","water"]', 3, 'Clouds are made of tiny water drops.', 10),
  ('science', 'K', 2, 'K.daynight', NULL, 'What do we see in the sky during the daytime?', '["The sun","Many stars","A lamp","The moon"]', 0, 'The sun lights up the daytime sky.', 10),
  ('science', 'K', 2, 'K.daynight', NULL, 'When do we usually see the moon and stars?', '["In the morning","Never","At noon","At night"]', 3, 'The moon and stars show up at night.', 10),
  ('science', 'K', 2, 'K.daynight', NULL, 'The sun gives us ___.', '["snow","rain","wind","light and warmth"]', 3, 'The sun gives Earth light and heat.', 10),
  ('science', 'K', 2, 'K.daynight', NULL, 'It is dark outside during the ___.', '["noon","sunrise","day","night"]', 3, 'Night is the dark part of the day.', 10),
  ('science', 'K', 2, 'K.daynight', NULL, 'We have day and night because the Earth ___.', '["melts","stops","spins","grows"]', 2, 'Earth spins, so different sides face the sun.', 10),
  ('science', 'K', 2, 'K.daynight', NULL, 'Which is brightest in the daytime sky?', '["A cloud","A star","The sun","The moon"]', 2, 'The sun is the brightest thing in our sky.', 10),
  ('science', 'K', 2, 'K.pushpull', NULL, 'When you open a drawer toward you, you ___ it.', '["push","pull","drop","eat"]', 1, 'Pulling brings something toward you.', 10),
  ('science', 'K', 2, 'K.pushpull', NULL, 'To make a swing go, you give it a ___.', '["color","drink","song","push"]', 3, 'A push makes the swing move away.', 10),
  ('science', 'K', 2, 'K.pushpull', NULL, 'A push or a pull can make something ___.', '["grow","move","melt","sing"]', 1, 'Pushes and pulls are forces that move things.', 10),
  ('science', 'K', 2, 'K.pushpull', NULL, 'Pulling a wagon makes it come ___ you.', '["toward","above","below","away from"]', 0, 'A pull brings the wagon toward you.', 10),
  ('science', 'K', 2, 'K.pushpull', NULL, 'Which one needs a push or pull to move?', '["A toy car","Your shadow","The wind","A star"]', 0, 'A toy car only moves when you push or pull it.', 10),
  ('science', 'K', 2, 'K.pushpull', NULL, 'Kicking a ball gives it a ___.', '["taste","smell","push","pull"]', 2, 'A kick is a push that sends the ball away.', 10),
  ('science', 'K', 2, 'K.animalneeds', NULL, 'Animals need ___ to live.', '["only sunlight","food, water, and air","nothing","only toys"]', 1, 'All animals need food, water, and air.', 10),
  ('science', 'K', 2, 'K.animalneeds', NULL, 'A fish needs ___ to live in.', '["fire","water","dry air","sand"]', 1, 'Fish live and breathe in water.', 10),
  ('science', 'K', 2, 'K.animalneeds', NULL, 'What do baby animals get from their parents?', '["Care and food","Money","Homework","Cars"]', 0, 'Parents help feed and protect their babies.', 10),
  ('science', 'K', 2, 'K.animalneeds', NULL, 'Birds build ___ to keep their eggs safe.', '["boxes of toys","swimming pools","cars","nests"]', 3, 'Birds build nests for their eggs.', 10),
  ('science', 'K', 2, 'K.animalneeds', NULL, 'Like people, animals need to ___ when they are tired.', '["read","sleep","drive","fly"]', 1, 'Animals rest and sleep to get their energy back.', 10),
  ('science', 'K', 2, 'K.animalneeds', NULL, 'A dog needs water to ___.', '["read","paint","drink","drive"]', 2, 'Animals drink water to stay alive.', 10),
